import json, re

lines = open('ios_crash.ips').readlines()
raw = ''.join(lines[1:])
raw = re.sub(r'"vmregioninfo"', '"vmregioninfo_lower"', raw)
crash = json.loads(raw)

# Check for nsexception, additionalInfo, etc.
for key in ['nsexception', 'trialInfo', 'legacyInfo', 'asi', 'lastExceptionBacktrace']:
    if key in crash:
        val = crash[key]
        if key == 'lastExceptionBacktrace':
            print(f"{key}: [{len(val)} frames]")
        elif isinstance(val, dict):
            print(f"{key}:")
            for k2, v2 in val.items():
                if isinstance(v2, (str, int, float, bool)):
                    print(f"  {k2}: {v2}")
                elif isinstance(v2, list) and all(isinstance(x, str) for x in v2):
                    for line in v2:
                        print(f"  {k2}: {line}")
                elif isinstance(v2, dict):
                    print(f"  {k2}: {v2}")
        else:
            print(f"{key}: {val}")

# Check all string fields for any exception messages
print("\n=== SEARCHING FOR EXCEPTION/ERROR MESSAGES ===")
def search_dict(d, path=""):
    if isinstance(d, dict):
        for k, v in d.items():
            search_dict(v, f"{path}.{k}")
    elif isinstance(d, list):
        for i, v in enumerate(d):
            if isinstance(v, str) and len(v) > 20:
                search_dict(v, f"{path}[{i}]")
    elif isinstance(d, str):
        lower = d.lower()
        if any(kw in lower for kw in ['exception', 'error', 'fault', 'null', 'crash', 'xaml', 'abort', 'unhandled']):
            print(f"  {path}: {d[:200]}")

search_dict(crash)

# Print more details about the app launch timing
print(f"\n=== TIMING ===")
print(f"  procLaunch: {crash.get('procLaunch')}")
print(f"  captureTime: {crash.get('captureTime')}")
print(f"  procStartAbsTime: {crash.get('procStartAbsTime')}")
print(f"  procExitAbsTime: {crash.get('procExitAbsTime')}")
if crash.get('procStartAbsTime') and crash.get('procExitAbsTime'):
    delta = crash['procExitAbsTime'] - crash['procStartAbsTime']
    # Absolute time is in Mach absolute time units - on ARM64 typically ~24MHz
    print(f"  delta ticks: {delta} (~{delta/24000000:.2f}s at 24MHz)")

